//! Long-running request codec
//!
//! Provides decoding for LongRunningRequest structures used in async long-running precompile calls (0x0805).
//! This codec extracts the delivery configuration needed for Phase 2 settlement,
//! as well as the HTTP URLs needed for RPC validation.

mod tests {
    use super::*;

    #[test]
    fn test_decode_delivery_config() {
        // This test would need actual ABI-encoded data
        // For now, just verify the struct can be created
        let config = DeliveryConfig {
            target: Address::ZERO,
            selector: FixedBytes::ZERO,
            gas_limit: 100_000,
            max_fee_per_gas: U256::from(1_000_000_000u64),
            max_priority_fee_per_gas: U256::from(100_000_000u64),
            value: U256::ZERO,
        };
        assert_eq!(config.gas_limit, 100_000);
    }
}

///
/// These fields are needed for Phase 2 settlement to properly call AsyncDelivery.deliver().
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DeliveryConfig {
    /// Target contract address for the callback
    pub target: Address,
    /// Function selector for the callback (4 bytes)
    pub selector: FixedBytes<4>,
    /// Maximum gas for the callback execution
    pub gas_limit: u64,
    /// Maximum fee per gas the user is willing to pay (EIP-1559)
    pub max_fee_per_gas: U256,
    /// Maximum priority fee per gas (tip) the user is willing to pay (EIP-1559)
    pub max_priority_fee_per_gas: U256,
    /// ETH value to send with the callback (0 for most cases)
    /// For long-running HTTP (0x0805): Not in ABI, returns 0
    /// For ZK two-phase (0x0806): Extracted from ABI field 11
    pub value: U256,
}

impl DeliveryConfig {
    /// Extract delivery configuration from ABI-encoded long-running request.

/// # Returns
/// * `Ok(DeliveryConfig)` - Extracted delivery configuration
/// * `Err(CodecError)` - If decoding fails
pub fn from_abi(data: &[u8]) -> Result<Self, CodecError> {
    // We need to decode enough fields to get the delivery config (fields 0-12)
    // But we can't know the full structure, so we'll decode just what we need
    let param_types = vec![
        // Base ExecutorRequest fields (0-4)
        ParamType::Address,                           // 0: executor
        ParamType::Array(Box::new(ParamType::Bytes)), // 1: encrypted_secrets (bytes[])
        ParamType::Uint(256),                         // 2: ttl
        ParamType::Array(Box::new(ParamType::Bytes)), // 3: secret_signature (bytes[])
        ParamType::Bytes,                             // 4: user_public_key
        // LongRunningRequest fields (5-13)
        ParamType::Uint(64),      // 5: poll_interval_blocks
        ParamType::Uint(64),      // 6: max_poll_block
        ParamType::String,        // 7: task_id_marker
        ParamType::Address,       // 8: delivery_target
        ParamType::FixedBytes(4), // 9: delivery_selector
        ParamType::Uint(256),     // 10: delivery_gas_limit
        ParamType::Uint(256),     // 11: delivery_max_fee_per_gas
        ParamType::Uint(256),     // 12: delivery_max_priority_fee_per_gas

/// # Returns
/// * `Ok(DeliveryConfig)` - Extracted delivery configuration
/// * `Err(CodecError)` - If decoding fails
pub fn from_zk_abi(data: &[u8]) -> Result<Self, CodecError> {
    let param_types = vec![
        // Base ExecutorRequest fields (0-4)
        ParamType::Address,                           // 0: executor
        ParamType::Array(Box::new(ParamType::Bytes)), // 1: encrypted_secrets (bytes[])
        ParamType::Uint(256),                         // 2: ttl
        ParamType::Array(Box::new(ParamType::Bytes)), // 3: secret_signature (bytes[])
        ParamType::Bytes,                             // 4: user_public_key
        // ZK-specific fields
        ParamType::Bool,          // 5: input_encrypted
        ParamType::Uint(64),      // 6: max_proof_block (Phase 2 deadline)
        ParamType::Address,       // 7: delivery_target
        ParamType::FixedBytes(4), // 8: delivery_selector
        ParamType::Uint(256),     // 9: delivery_gas_limit
        ParamType::Uint(256),     // 10: delivery_max_fee_per_gas
        ParamType::Uint(256),     // 11: delivery_max_priority_fee_per_gas
        ParamType::Uint(256),     // 12: delivery_value
        ParamType::Bytes,         // 13: operation_input
    ];

/// # Returns
/// * `Ok(DeliveryConfig)` - Extracted delivery configuration
/// * `Err(CodecError)` - If decoding fails
pub fn from_sovereign_agent_abi(data: &[u8]) -> Result<Self, CodecError> {
    // StorageRef tuple type: (string, string, string)
    let storage_ref_type = ParamType::Tuple(vec![
        ParamType::String, // platform
        ParamType::String, // path
        ParamType::String, // key_ref
    ]);

    // NOTE: This decoder only extracts delivery config (fields 6-10) from the Sovereign Agent ABI.
    // It intentionally uses 22 param types (fields 0-21) even though the full ABI has 23
    // (rpc_urls at field 22). The ABI decoder tolerates trailing data — offsets are absolute,
    // so the 22-type decoder reads the correct head slots. rpc_urls is not needed here.
    let param_types = vec![
        // Base ExecutorRequest fields (0-2) - simplified
        ParamType::Address,   // 0: executor
        ParamType::Uint(256), // 1: ttl
        ParamType::Bytes,     // 2: user_public_key
        // Long-running polling config (3-5)
        ParamType::Uint(64), // 3: poll_interval_blocks

/// # Returns
/// * `Ok(DeliveryConfig)` - Extracted delivery configuration
/// * `Err(CodecError)` - If decoding fails
pub fn from_persistent_agent_abi(data: &[u8]) -> Result<Self, CodecError> {
    let param_types = vec![
        // Base ExecutorRequest fields (0-4)
        ParamType::Address,                           // 0: executor
        ParamType::Array(Box::new(ParamType::Bytes)), // 1: encrypted_secrets (bytes[])
        ParamType::Uint(256),                         // 2: ttl
        ParamType::Array(Box::new(ParamType::Bytes)), // 3: secret_signature (bytes[])
        ParamType::Bytes,                             // 4: user_public_key
        // Phase 2 config
        ParamType::Uint(64), // 5: max_spawn_block
        // Delivery config (6-11)
        ParamType::Address,       // 6: delivery_target
        ParamType::FixedBytes(4), // 7: delivery_selector
        ParamType::Uint(256),     // 8: delivery_gas_limit
        ParamType::Uint(256),     // 9: delivery_max_fee_per_gas
        ParamType::Uint(256),     // 10: delivery_max_priority_fee_per_gas
        ParamType::Uint(256),     // 11: delivery_value
    ];

/// # Returns
/// * `Ok(u64)` - The output size in bytes
/// * `Err(CodecError)` - If decoding fails
pub fn extract_fhe_output_size(data: &[u8]) -> Result<u64, CodecError> {
    let param_types = vec![
        ParamType::Bool,           // 0: has_error
        ParamType::String,         // 1: output_uri
        ParamType::FixedBytes(32), // 2: output_content_hash
        ParamType::Uint(64),       // 3: output_size_bytes
        ParamType::String,         // 4: error_message
    ];

    let tokens = ethabi::decode(&param_types, data).map_err(|e| {
        CodecError::FieldExtractionFailed(format!("ethabi decode failed (FHE result): {}", e))
    })?;

    if tokens.len() < 4 {
        return Err(CodecError::FieldExtractionFailed(format!(
            "Expected at least 4 tokens for FHE result, got {}",
            tokens.len()
        )));
    }

